def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                weight = (a * 0.75) if a % 2 == 0 else (a * 1.25)
                temp = np.cos(ratio * a * np.pi) * (a ** 3) / (weight + 1)
                if a % 4 == 1:
                    temp *= 1.1
                else:
                    temp *= 0.95
                score += np.abs(temp)
            if int(capacity) % 2 == 1 and int(item) % 3 == 0:
                score *= 0.8
            if score > 12:
                score /= 3.1
        elif 0.05 <= ratio < 0.2:
            acc_mul = 1.0
            for n in range(1, int(capacity) + 3):
                acc_mul *= np.tanh(ratio + n/ (n+2))
                if acc_mul > 500:
                    acc_mul = np.sqrt(acc_mul)
                    break
            shift = (int(acc_mul * 7) % 350)
            score += np.log1p(ratio * shift + 2)
            if (int(capacity) % 4 == 0) and ((item * 5) % 4 == 1):
                score += 5.2
            else:
                score -= 1.1
            extra_sum = 0
            for x in range(1, 8):
                fract_part = ((ratio * (x**3)) % 1)
                extra_sum += fract_part * (x ** 1.8)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(2, 10):
                increment = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 1) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 5 == 0:
                score *= 1.35
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            diff = ratio - 0.5
            for p in range(1, 15):
                term = ((diff) ** p) * (p ** 1.8)
                if term > 70:
                    term = np.log1p(term)
                penalty_base += term
            score = penalty_base * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 6) % 8 == 0) and (int(item * 7) % 9 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 1.7 + 7
            if score > 180:
                score = 180
        elif 0.85 < ratio <= 1.25:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 0.9)
            score = penalty_ext * 30
            if capacity < item * 1.45:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 3 == 1):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.75)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.75
            if score > 2500:
                score = 2500
        else:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.log1p(term ** 0.7)
                super_penalty += term
            score = super_penalty * 40
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 14) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 15
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.8 + 6
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 8:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = (np.max(finite_priorities) + median_val) * (10 + top_count) / 2
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
